__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step_arg)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (borderCols << 1);
    const int small_block_rows = BLOCK_SIZE - (borderRows << 1);

    const int blkX = bx * small_block_cols - borderCols;
    const int blkY = by * small_block_rows - borderRows;

    const int x = blkX + tx;
    const int y = blkY + ty;

    const float amb = 80.0f;
    const float step = step_arg * 0.001f;
    const float Cap_1 = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    __local float temp_curr[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp_next[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_local[BLOCK_SIZE][BLOCK_SIZE];

    if (x >= 0 && x < col && y >= 0 && y < row) {
        const int idx = y * col + x;
        temp_curr[ty][tx] = temp_src[idx];
        power_local[ty][tx] = power[idx];
    } else {
        temp_curr[ty][tx] = amb;
        power_local[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int it = 0; it < iteration; ++it) {
        const int valid_min = it + 1;
        const int valid_max_x = BLOCK_SIZE - it - 1;
        const int valid_max_y = BLOCK_SIZE - it - 1;

        if (tx >= valid_min && tx < valid_max_x &&
            ty >= valid_min && ty < valid_max_y &&
            x >= 0 && x < col && y >= 0 && y < row) {

            const float center = temp_curr[ty][tx];
            const float p = power_local[ty][tx];
            float delta;

            if (y == 0 && x == 0) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx + 1] - center) * Rx_1 +
                                 (temp_curr[ty + 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (y == 0 && x == col - 1) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx - 1] - center) * Rx_1 +
                                 (temp_curr[ty + 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (y == row - 1 && x == col - 1) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx - 1] - center) * Rx_1 +
                                 (temp_curr[ty - 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (y == row - 1 && x == 0) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx + 1] - center) * Rx_1 +
                                 (temp_curr[ty - 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (y == 0) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx + 1] + temp_curr[ty][tx - 1] - 2.0f * center) * Rx_1 +
                                 (temp_curr[ty + 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (x == col - 1) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty + 1][tx] + temp_curr[ty - 1][tx] - 2.0f * center) * Ry_1 +
                                 (temp_curr[ty][tx - 1] - center) * Rx_1 +
                                 (amb - center) * Rz_1);
            } else if (y == row - 1) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty][tx + 1] + temp_curr[ty][tx - 1] - 2.0f * center) * Rx_1 +
                                 (temp_curr[ty - 1][tx] - center) * Ry_1 +
                                 (amb - center) * Rz_1);
            } else if (x == 0) {
                delta = Cap_1 * (p +
                                 (temp_curr[ty + 1][tx] + temp_curr[ty - 1][tx] - 2.0f * center) * Ry_1 +
                                 (temp_curr[ty][tx + 1] - center) * Rx_1 +
                                 (amb - center) * Rz_1);
            } else {
                delta = Cap_1 * (p +
                                 (temp_curr[ty + 1][tx] + temp_curr[ty - 1][tx] - 2.0f * center) * Ry_1 +
                                 (temp_curr[ty][tx + 1] + temp_curr[ty][tx - 1] - 2.0f * center) * Rx_1 +
                                 (amb - center) * Rz_1);
            }

            temp_next[ty][tx] = center + delta;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx >= valid_min && tx < valid_max_x &&
            ty >= valid_min && ty < valid_max_y &&
            x >= 0 && x < col && y >= 0 && y < row) {
            temp_curr[ty][tx] = temp_next[ty][tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (tx >= iteration && tx < BLOCK_SIZE - iteration &&
        ty >= iteration && ty < BLOCK_SIZE - iteration &&
        x >= 0 && x < col && y >= 0 && y < row) {
        temp_dst[y * col + x] = temp_curr[ty][tx];
    }
}
